using UnityEngine;\nusing UnityEngine.UI;\nusing TMPro;\n\npublic class PlayerDashboard : MonoBehaviour\n{\n    [SerializeField] private TextMeshProUGUI playerNameText;\n    [SerializeField] private TextMeshProUGUI countryFlagText;\n    [SerializeField] private TextMeshProUGUI countryNameText;\n    [SerializeField] private TextMeshProUGUI totalScoreText;\n    [SerializeField] private TextMeshProUGUI currentLevelText;\n    [SerializeField] private TextMeshProUGUI levelPositionText;\n    [SerializeField] private TextMeshProUGUI levelsCompletedText;\n    [SerializeField] private TextMeshProUGUI enemiesDefeatedText;\n    [SerializeField] private TextMeshProUGUI gamesPlayedText;\n    [SerializeField] private TextMeshProUGUI averageScoreText;\n    [SerializeField] private Image playerAvatarImage;\n    [SerializeField] private Transform leaderboardContent;\n    [SerializeField] private GameObject leaderboardEntryPrefab;\n    [SerializeField] private Canvas dashboardPanel;\n    [SerializeField] private Button closeDashboardButton;\n    [SerializeField] private Button editProfileButton;\n\n    private LayoutGroup leaderboardLayout;\n\n    private void Start()\n    {\n        if (closeDashboardButton != null)\n            closeDashboardButton.onClick.AddListener(CloseDashboard);\n        \n        if (editProfileButton != null)\n            editProfileButton.onClick.AddListener(OpenEditProfile);\n\n        UpdateDashboard();\n    }\n\n    public void UpdateDashboard()\n    {\n        if (PlayerProfileManager.Instance == null)\n            return;\n\n        PlayerProfile profile = PlayerProfileManager.Instance.GetPlayerProfile();\n\n        // Update player info\n        if (playerNameText != null)\n            playerNameText.text = profile.playerName;\n\n        if (countryFlagText != null)\n            countryFlagText.text = PlayerProfileManager.Instance.GetCountryFlag(profile.countryCode);\n\n        if (countryNameText != null)\n            countryNameText.text = profile.countryName;\n\n        // Update statistics\n        if (totalScoreText != null)\n            totalScoreText.text = $\"Total Score: <color=yellow>{profile.totalScore}</color>\";\n\n        if (currentLevelText != null)\n            currentLevelText.text = $\"Current Level: <color=lime>{profile.currentLevel}</color>\";\n\n        if (levelPositionText != null)\n            levelPositionText.text = $\"Position: <color=orange>#{profile.rank}</color>\";\n\n        if (levelsCompletedText != null)\n            levelsCompletedText.text = $\"Levels Completed: <color=cyan>{profile.totalLevelsCompleted}</color>\";\n\n        if (enemiesDefeatedText != null)\n            enemiesDefeatedText.text = $\"Enemies Defeated: <color=red>{profile.totalEnemiesDefeated}</color>\";\n\n        if (gamesPlayedText != null)\n            gamesPlayedText.text = $\"Games Played: <color=magenta>{profile.gamesPlayed}</color>\";\n\n        // Calculate and display average score\n        float avgScore = profile.gamesPlayed > 0 ? (float)profile.totalScore / profile.gamesPlayed : 0;\n        if (averageScoreText != null)\n            averageScoreText.text = $\"Avg Score/Game: <color=green>{avgScore:F0}</color>\";\n\n        // Update leaderboard\n        UpdateLeaderboard();\n    }\n\n    private void UpdateLeaderboard()\n    {\n        if (leaderboardContent == null)\n            return;\n\n        // Clear existing leaderboard entries\n        foreach (Transform child in leaderboardContent)\n        {\n            Destroy(child.gameObject);\n        }\n\n        // Create leaderboard entries (mock data for now)\n        CreateLeaderboardEntry(1, \"Champion Pro\", \"🇺🇸\", 25000);\n        CreateLeaderboardEntry(2, \"Master Player\", \"🇮🇳\", 22500);\n        CreateLeaderboardEntry(3, \"Elite Gamer\", \"🇬🇧\", 20000);\n        CreateLeaderboardEntry(4, \"Pro Level\", \"🇨🇦\", 18500);\n        CreateLeaderboardEntry(5, \"Your Rank\", \"🇵🇰\", 15000, true);\n    }\n\n    private void CreateLeaderboardEntry(int rank, string playerName, string flag, int score, bool isYou = false)\n    {\n        if (leaderboardEntryPrefab == null)\n        {\n            // Create dynamic leaderboard entry if prefab doesn't exist\n            GameObject entryGO = new GameObject($\"LeaderboardEntry_{rank}\");\n            entryGO.transform.SetParent(leaderboardContent);\n\n            TextMeshProUGUI rankText = entryGO.AddComponent<TextMeshProUGUI>();\n            rankText.text = $\"<b>#{rank}</b> {flag} {playerName}: <color=yellow>{score}</color>\";\n            rankText.fontSize = 4;\n            \n            LayoutElement layout = entryGO.AddComponent<LayoutElement>();\n            layout.preferredHeight = 30;\n\n            if (isYou)\n            {\n                rankText.color = Color.green;\n            }\n        }\n        else\n        {\n            // Use prefab if it exists\n            GameObject entry = Instantiate(leaderboardEntryPrefab, leaderboardContent);\n            TextMeshProUGUI[] texts = entry.GetComponentsInChildren<TextMeshProUGUI>();\n            if (texts.Length >= 2)\n            {\n                texts[0].text = $\"#{rank}\";\n                texts[1].text = $\"{flag} {playerName} - {score}\";\n            }\n        }\n    }\n\n    public void OpenDashboard()\n    {\n        if (dashboardPanel != null)\n        {\n            dashboardPanel.gameObject.SetActive(true);\n            UpdateDashboard();\n        }\n    }\n\n    public void CloseDashboard()\n    {\n        if (dashboardPanel != null)\n        {\n            dashboardPanel.gameObject.SetActive(false);\n        }\n    }\n\n    private void OpenEditProfile()\n    {\n        Debug.Log(\"Opening edit profile\");\n        // TODO: Implement edit profile UI\n    }\n}\n"